import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useNavigate, useLocation } from 'react-router-dom';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { useLanguage } from '@/app/providers/LanguageContext.jsx';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { authService, tokenService } from '@/features/auth/services';
import { profileService } from '@/features/settings/services';
import { LoadingSpinner, LanguageSelector } from '@/shared/components';
import { maskEmail } from '@/shared/utils/format-utils.js';
import logger from '@/shared/utils/logger.js';
import i18n from '@/app/config/i18n/config/i18n.js';

import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

function TwoFactorAuth() {
  const { t, ready } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { theme, effectiveTheme, updateTheme } = useTheme();
  const { changeLanguage } = useLanguage();
  const { success } = useToast();

  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const [isI18nReady, setIsI18nReady] = useState(i18n.isInitialized);

  const inputRefs = useRef([]);

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;
  const userId = location.state?.userId;
  const userEmail = location.state?.email;

  // Sync window width for responsiveness
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      if (resizeTimer) { clearTimeout(resizeTimer); }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) { clearTimeout(resizeTimer); }
    };
  }, []);

  // Ensure i18n is ready
  useEffect(() => {
    let cleanup = null;
    const checkI18nReady = async () => {
      if (i18n.isInitialized) {
        if (!i18n.hasResourceBundle(i18n.language, 'auth')) {
          await i18n.loadNamespaces('auth');
        }
        setIsI18nReady(true);
      } else {
        const handleInitialized = () => {
          i18n.loadNamespaces('auth').then(() => {
            setIsI18nReady(true);
          });
        };
        i18n.on('initialized', handleInitialized);
        cleanup = () => {
          i18n.off('initialized', handleInitialized);
        };
      }
    };
    checkI18nReady();
    return () => {
      if (cleanup) { cleanup(); }
    };
  }, []);

  const handleBackToSignIn = () => {
    navigate('/login');
  };

  const handleThemeToggle = () => {
    const nextTheme = theme === 'light' ? 'dark' : theme === 'dark' ? 'auto' : 'light';
    updateTheme(nextTheme);
  };

  const handleChange = (element, index) => {
    if (isNaN(element.value)) return false;

    setOtp([...otp.map((d, idx) => (idx === index ? element.value : d))]);

    if (element.value !== '' && index < 5) {
      inputRefs.current[index + 1].focus();
    }

    if (error) setError('');
  };

  const handleKeyDown = (e, index) => {
    if (e.key === 'Backspace') {
      if (otp[index] === '' && index > 0) {
        inputRefs.current[index - 1].focus();
      }
    }
  };

  const handlePaste = (e) => {
    const data = e.clipboardData.getData('text').slice(0, 6);
    if (!/^\d+$/.test(data)) return;

    const dataArray = data.split('');
    const newOtp = [...otp];
    dataArray.forEach((char, index) => {
      if (index < 6) newOtp[index] = char;
    });
    setOtp(newOtp);

    const lastIdx = dataArray.length < 6 ? dataArray.length : 5;
    inputRefs.current[lastIdx].focus();
  };

  const handleTwoFactorSubmit = async (e) => {
    if (e) { e.preventDefault(); }
    setError('');

    const code = otp.join('');

    if (code.length !== 6) {
      setError(t('pleaseEnter6DigitCode', { ns: 'auth' }));
      return;
    }

    if (!userId) {
      setError(t('authenticationSessionExpired', { ns: 'auth' }));
      setTimeout(() => navigate('/login'), 2000);
      return;
    }

    setLoading(true);

    try {
      const data = await authService.verifyTwoFactorAuth(userId, code);

      if (data.code === '00' && data.data) {
        const responseData = data.data;
        const user = responseData.user;
        const tokens = responseData.tokens;

        const userTypeValue = user.userType || user.user_type || user.usertype || 'individual';

        tokenService.setAuthData({
          token: tokens.accessToken,
          refreshToken: tokens.refreshToken,
          user: {
            ...user,
            userType: userTypeValue,
            user_type: userTypeValue,
            usertype: userTypeValue
          }
        });

        tokenService.setUserType(userTypeValue);
        localStorage.setItem('twoFactorEnabled', 'true');

        if (responseData.verificationLevel !== undefined) {
          tokenService.setVerificationLevel(responseData.verificationLevel);
        } else if (user.verificationLevel !== undefined) {
          tokenService.setVerificationLevel(user.verificationLevel);
        }

        if (user.wallet_balance !== undefined) {
          tokenService.setWalletBalance(user.wallet_balance);
        }

        try {
          const [profileResult, prefsResult] = await Promise.allSettled([
            profileService.getUserProfile(),
            profileService.getUserPreferences(),
          ]);

          const profile = profileResult.status === 'fulfilled' ? profileResult.value?.data ?? profileResult.value ?? {} : {};
          const prefs = prefsResult.status === 'fulfilled' ? prefsResult.value?.data ?? prefsResult.value ?? {} : {};

          const existingUserData = JSON.parse(localStorage.getItem('userData') || '{}');
          const loginUserId = user.id || existingUserData.id;
          const merged = {
            ...existingUserData,
            ...profile,
            id: loginUserId,
            preferences: {
              currency: prefs.currency || existingUserData.preferences?.currency || 'GHS',
              language: prefs.language || existingUserData.preferences?.language || 'en',
              notification_preference: prefs.notification_preference || prefs.notificationPreference || existingUserData.preferences?.notification_preference || 'email',
              theme: prefs.theme || existingUserData.preferences?.theme || 'light',
              timezone: prefs.timezone || existingUserData.preferences?.timezone || 'Africa/Accra',
            },
            updated_at: new Date().toISOString(),
          };
          localStorage.setItem('userData', JSON.stringify(merged));

          if (merged.preferences.language) {
            await changeLanguage(merged.preferences.language);
          }
          if (merged.preferences.theme) {
            updateTheme(merged.preferences.theme);
          }
        } catch (error) {
          logger.error('Error loading preferences', { error });
        }

        setOtp(['', '', '', '', '', '']);
        success(t('loginSuccessfulExclamation', { ns: 'auth' }));
        setTimeout(() => navigate('/dashboard'), 500);
      } else {
        throw new Error(data.message || t('twoFactorVerificationFailed', { ns: 'auth' }));
      }
    } catch (err) {
      setError(err.message || t('invalidAuthenticationCode', { ns: 'auth' }));
    } finally {
      setLoading(false);
    }
  };

  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;

  const responsiveStyles = {
    paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '48px',
    logoWidth: isSmallMobile ? '90px' : isMobile ? '110px' : isTablet ? '140px' : '160px'
  };

  if (!ready && !isI18nReady) {
    return (
      <div className="login-container" style={{
        backgroundColor: effectiveTheme === 'dark' ? '#0a0a0a' : '#f5f5f5'
      }}>
        <LoadingSpinner size="large" />
      </div>
    );
  }

  const animationStyles = `
    @keyframes minimal-pulse {
      0% { transform: scale(1); opacity: 0.8; }
      50% { transform: scale(1.05); opacity: 1; }
      100% { transform: scale(1); opacity: 0.8; }
    }
    @keyframes slide-in-top {
      from { opacity: 0; transform: translateY(-20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    @keyframes soft-glow {
      from { border-color: var(--border-secondary); }
      to { border-color: var(--accent); box-shadow: 0 0 10px rgba(var(--accent-rgb), 0.1); }
    }
    .otp-box:focus {
      animation: soft-glow 0.3s forwards;
      outline: none;
      background: var(--bg-hover) !important;
    }
    .minimal-card {
      backdrop-filter: blur(16px);
      -webkit-backdrop-filter: blur(16px);
      background: ${effectiveTheme === 'dark' ? 'rgba(26, 26, 26, 0.85)' : 'rgba(255, 255, 255, 0.9)'};
      border: 1px solid var(--border-primary);
      box-shadow: var(--shadow-xl);
    }
    .neutral-title {
      color: var(--text-primary);
      font-weight: 800;
      letter-spacing: -1px;
    }
    @keyframes subtleFloat {
      0%, 100% { transform: translate(0, 0); }
      50% { transform: translate(10px, -10px); }
    }
    .bg-mesh-toned {
      position: fixed;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: radial-gradient(circle at 20% 30%, rgba(0, 0, 0, 0.02) 0%, transparent 50%),
                  radial-gradient(circle at 80% 70%, rgba(0, 0, 0, 0.02) 0%, transparent 50%);
      pointer-events: none;
      z-index: -2;
      animation: subtleFloat 30s ease-in-out infinite;
    }
  `;

  if (!userId) {
    return (
      <div className="login-container">
        <style>{animationStyles}</style>
        <div className="bg-mesh-toned"></div>
        <div className="login-form minimal-card" style={{ maxWidth: '420px', textAlign: 'center', position: 'relative', paddingTop: responsiveStyles.paddingTop, animation: 'slide-in-top 0.6s ease-out' }}>


          <div style={{
            position: 'absolute',
            top: '20px',
            right: '20px',
            zIndex: 10,
          }}>
            <LanguageSelector />
          </div>

          <img src={logoSrc} alt="iSmartPay Logo" className="login-logo" style={{ maxWidth: responsiveStyles.logoWidth, animation: 'logoEntrance 0.8s ease-out' }} />

          <h2 className="neutral-title" style={{ marginBottom: '16px', fontSize: '24px' }}>{t('sessionExpiredTitle', { ns: 'auth' })}</h2>
          <p style={{ marginBottom: '32px', color: 'var(--text-muted)', fontSize: '15px' }}>{t('sessionExpiredMessage', { ns: 'auth' })}</p>

          <button type="button" onClick={() => navigate('/login')} style={{ backgroundColor: 'var(--success)', color: 'white', borderRadius: '12px', fontWeight: '700', padding: '16px' }}>
            {t('backToSignIn', { ns: 'auth' })}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="login-container">
      <style>{animationStyles}</style>
      <div className="bg-mesh-toned"></div>
      <form className="login-form minimal-card" onSubmit={handleTwoFactorSubmit} style={{
        position: 'relative',
        paddingTop: responsiveStyles.paddingTop,
        animation: 'slide-in-top 0.6s cubic-bezier(0.16, 1, 0.3, 1)',
        maxWidth: '460px'
      }}>


        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>

        <div style={{ textAlign: 'center', marginBottom: '32px' }}>
          <img
            src={logoSrc}
            alt="iSmartPay Logo"
            className="login-logo"
            style={{
              transition: 'opacity var(--transition-theme)',
              opacity: 1,
              maxWidth: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
              marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
              marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '32px'
            }}
          />
          <h1 className="neutral-title" style={{ fontSize: '28px', margin: '0 0 8px' }}>2FA</h1>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px', fontWeight: '500', margin: 0 }}>{t('enterCodeFromAuthenticator', { ns: 'auth' })}</p>
        </div>

        {userEmail && (
          <div style={{ textAlign: 'center', marginBottom: '32px' }}>
            <span style={{
              color: 'var(--text-secondary)', fontSize: '14px', fontWeight: '600',
              padding: '4px 12px', borderRadius: '8px',
              background: 'var(--bg-input)',
              border: '1px solid var(--border-primary)',
              display: 'inline-block'
            }}>
              {maskEmail(userEmail)}
            </span>
          </div>
        )}

        {error && (
          <div className="error" role="alert" style={{ borderRadius: '12px', padding: '12px', fontSize: '14px', marginBottom: '24px' }}>
            <i className="fa-solid fa-triangle-exclamation" style={{ marginRight: '8px' }}></i>
            {error}
          </div>
        )}

        <div style={{ display: 'flex', justifyContent: 'center', gap: isSmallMobile ? '8px' : '12px', marginBottom: '32px' }}>
          {otp.map((data, index) => (
            <input key={index} type="text" inputMode="numeric" maxLength="1" ref={(el) => (inputRefs.current[index] = el)}
              value={data} onChange={(e) => handleChange(e.target, index)} onKeyDown={(e) => handleKeyDown(e, index)} onPaste={handlePaste}
              className="otp-box"
              style={{
                width: isSmallMobile ? '42px' : '52px', height: isSmallMobile ? '52px' : '64px',
                textAlign: 'center', fontSize: '24px', fontWeight: '800', borderRadius: '12px',
                border: '1px solid var(--border-secondary)', backgroundColor: 'var(--bg-input)', color: 'var(--text-primary)',
                transition: 'all 0.2s ease', fontFamily: 'Inter, sans-serif'
              }} />
          ))}
        </div>

        <button type="submit" disabled={loading}
          style={{
            opacity: loading ? 0.7 : 1, position: 'relative', overflow: 'hidden',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
            padding: '16px', fontSize: '16px', fontWeight: '700', borderRadius: '12px',
            background: 'var(--accent)', border: 'none', color: 'white',
            boxShadow: 'var(--shadow-md)'
          }}>
          {loading ? t('verifying', { ns: 'auth', defaultValue: 'Verifying...' }) : t('verifyCode', { ns: 'auth' })}
        </button>

        {loading && createPortal(
          <div style={{
            position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
            backgroundColor: effectiveTheme === 'dark' ? 'rgba(0, 0, 0, 0.8)' : 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(8px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 99999
          }}>
            <div className="minimal-card" style={{ borderRadius: '24px', padding: '48px', display: 'flex', flexDirection: 'column', alignItems: 'center', minWidth: '160px' }}>
              <LoadingSpinner size="large" />
              <p style={{ marginTop: '20px', fontWeight: '600', color: 'var(--text-primary)' }}>{t('verifying', { ns: 'auth', defaultValue: 'Verifying...' })}</p>
            </div>
          </div>, document.body
        )}

        <div style={{ margin: '32px 0 24px', display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{ flex: 1, height: '1px', background: 'var(--border-primary)' }}></div>
          <p style={{ margin: 0, fontSize: '13px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('havingTrouble', { ns: 'auth' })}</p>
          <div style={{ flex: 1, height: '1px', background: 'var(--border-primary)' }}></div>
        </div>

        <button type="button" onClick={handleBackToSignIn}
          style={{
            backgroundColor: 'transparent', color: 'var(--success)', border: '1px solid var(--success)',
            borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center',
            gap: '8px', fontSize: '14px', fontWeight: '600', padding: '14px', transition: 'all 0.2s ease'
          }}
          onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(16, 185, 129, 0.05)'; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}>
          <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>arrow_back</span>
          {t('backToSignIn', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
}

export default TwoFactorAuth;
